mapper.insert:
INSERT INTO unit_price (
    unit_price_id, code, region, dormitory_id, room_id, usage_type_code,
    daily_unit_price, created_at, updated_at
) VALUES (
    #{unitPriceId}, #{code}, #{region}, #{dormitoryId}, #{roomId}, #{usageTypeCode},
    #{dailyUnitPrice}, #{createdAt}, #{updatedAt}
)

mapper.update:
UPDATE unit_price
SET deleted_at = #{deletedAt}, updated_at = #{deletedAt}
WHERE unit_price_id = #{unitPriceId} AND deleted_at IS NULL

mapper.select:
SELECT up.unit_price_id, up.code, up.region, rg.name AS region_name, up.dormitory_id, d.name AS dormitory_name, up.room_id, r.room_name, up.usage_type_code, ut.name AS usage_type_name, up.daily_unit_price, up.created_at, up.updated_at FROM unit_price up LEFT JOIN region rg ON rg.code = up.region AND rg.deleted_at IS NULL LEFT JOIN dormitory d ON d.dormitory_id = up.dormitory_id AND d.deleted_at IS NULL LEFT JOIN room r ON r.room_id = up.room_id AND r.deleted_at IS NULL LEFT JOIN usage_type ut ON ut.code = up.usage_type_code AND ut.deleted_at IS NULL WHERE up.deleted_at IS NULL
AND up.code ILIKE CONCAT('%', #{code}, '%')
AND up.region = #{region}
AND up.dormitory_id = #{dormitoryId}
AND up.usage_type_code = #{usageTypeCode}
ORDER BY up.code LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM unit_price up
WHERE up.deleted_at IS NULL

    AND up.code ILIKE CONCAT('%', #{code}, '%')


    AND up.region = #{region}


    AND up.dormitory_id = #{dormitoryId}


